/**
 * Explorable engine seed — Solar System.
 *
 * Moves the formerly-hardcoded planet content into the DB so the explorer is
 * data-driven (CLAUDE.md §16 r5). Uses the Supabase service role (bypasses RLS).
 * Idempotent: upserts the explorer by key, replaces its nodes.
 *
 * Run: node --env-file=.env.local scripts/seed-explorers.mjs
 * Flags:
 *   --dry-run   Print what would be written without touching the DB
 *   --unpublish Seed but leave is_published = false (admin spot-check first)
 */

import { createClient } from '@supabase/supabase-js'

const args = process.argv.slice(2)
const DRY_RUN = args.includes('--dry-run')
const PUBLISH = !args.includes('--unpublish')
// --sql emits idempotent SQL to stdout instead of writing via the client.
// Use this when no local SUPABASE_SERVICE_ROLE_KEY is available (apply via the
// Supabase SQL editor / MCP). The service-role client path is the default.
const SQL_MODE = args.includes('--sql')

const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL
const SERVICE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY
if (!SQL_MODE && (!SUPABASE_URL || !SERVICE_KEY)) {
  console.error('Missing NEXT_PUBLIC_SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY (use --env-file=.env.local), or pass --sql to emit SQL')
  process.exit(1)
}

