const ATLAS_NODES = COUNTRIES.map((c, i) => ({
  key: c.key,
  name: c.name,
  order_index: i,
  visual: { color: c.color, lat: c.lat, lng: c.lng, continent: c.continent, wonderType: c.wonderType, whatIf: c.whatIf },
  stats: { capital: c.capital, population: c.population, area: c.area, flag: c.flag },
  content: { narration: c.narration, layers: c.layers },
  quiz: null,
}))

// All explorers seeded by this script.
const DATASETS = [
  { explorer: SOLAR_SYSTEM, nodes: NODES },
  { explorer: WORLD_ATLAS, nodes: ATLAS_NODES },
]

// PostgreSQL literal helpers for --sql mode.
const sqlStr = (v) => (v == null ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`)
const sqlJson = (v) => (v == null ? 'NULL' : `'${JSON.stringify(v).replace(/'/g, "''")}'::jsonb`)

function emitSql() {
  const lines = []
  lines.push('-- Generated by scripts/seed-explorers.mjs --sql. Idempotent.')
  lines.push('BEGIN;')
  for (const { explorer: e, nodes } of DATASETS) {
    lines.push(`INSERT INTO explorers (key, title, tagline, emoji, scene_type, gradient, config, order_index, is_published, updated_at)`)
    lines.push(`VALUES (${sqlStr(e.key)}, ${sqlStr(e.title)}, ${sqlStr(e.tagline)}, ${sqlStr(e.emoji)}, ${sqlStr(e.scene_type)}, ${sqlStr(e.gradient)}, ${sqlJson(e.config)}, ${e.order_index}, ${PUBLISH}, now())`)
    lines.push(`ON CONFLICT (key) DO UPDATE SET title = EXCLUDED.title, tagline = EXCLUDED.tagline, emoji = EXCLUDED.emoji, scene_type = EXCLUDED.scene_type, gradient = EXCLUDED.gradient, config = EXCLUDED.config, order_index = EXCLUDED.order_index, is_published = EXCLUDED.is_published, updated_at = now();`)
    lines.push(`DELETE FROM explorer_nodes WHERE explorer_id = (SELECT id FROM explorers WHERE key = ${sqlStr(e.key)});`)
    for (const n of nodes) {
      lines.push(`INSERT INTO explorer_nodes (explorer_id, key, name, order_index, visual, stats, content, quiz)`)
      lines.push(`VALUES ((SELECT id FROM explorers WHERE key = ${sqlStr(e.key)}), ${sqlStr(n.key)}, ${sqlStr(n.name)}, ${n.order_index}, ${sqlJson(n.visual)}, ${sqlJson(n.stats)}, ${sqlJson(n.content)}, ${sqlJson(n.quiz)});`)
    }
  }
  lines.push('COMMIT;')
  console.log(lines.join('\n'))
}

async function seedOne(supabase, e, nodes) {
  const { data: explorer, error: upsertErr } = await supabase
    .from('explorers')
    .upsert(
      {
        key: e.key,
        title: e.title,
        tagline: e.tagline,
        emoji: e.emoji,
        scene_type: e.scene_type,
        gradient: e.gradient,
        config: e.config,
        order_index: e.order_index,
        is_published: PUBLISH,
        updated_at: new Date().toISOString(),
      },
      { onConflict: 'key' },
    )
    .select('id')
    .single()
  if (upsertErr) throw upsertErr

  // Replace nodes for a clean idempotent re-seed.
  const { error: delErr } = await supabase.from('explorer_nodes').delete().eq('explorer_id', explorer.id)
  if (delErr) throw delErr

  const rows = nodes.map((n) => ({
    explorer_id: explorer.id,
    key: n.key,
    name: n.name,
    order_index: n.order_index,
    visual: n.visual,
    stats: n.stats,
    content: n.content,
    quiz: n.quiz,
  }))
  const { error: insErr } = await supabase.from('explorer_nodes').insert(rows)
  if (insErr) throw insErr

  console.log(`✓ Seeded explorer "${e.key}" (${explorer.id}) with ${rows.length} nodes.`)
}

async function main() {
  if (SQL_MODE) { emitSql(); return }

  console.log(`Seeding ${DATASETS.length} explorers (publish=${PUBLISH}, dryRun=${DRY_RUN})`)
  if (DRY_RUN) {
    console.log(JSON.stringify(DATASETS.map(d => ({ key: d.explorer.key, nodeCount: d.nodes.length })), null, 2))
    return
  }

  const supabase = createClient(SUPABASE_URL, SERVICE_KEY, { auth: { persistSession: false } })
  for (const { explorer, nodes } of DATASETS) {
    await seedOne(supabase, explorer, nodes)
  }
}

main().catch((e) => {
  console.error('Seed failed:', e.message ?? e)
  process.exit(1)
})
